// build-strategy-synthesis — Validate Upstream Inputs
// Checks all required upstream artifacts are present and well-formed.
// This is a cross-artifact synthesis phase: all four planning artifacts must be present.
//
// CLOUD MODE: all data arrives inline via n8n pipeline.
//             No filesystem access required.

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const input = $input.first().json;
const storeProfile = input.store_profile;
const marketIntelligence = input.market_intelligence;
const brandPositioning = input.brand_positioning;
const competitorClusters = input.competitor_clusters;
const intakePayload = input.normalized_intake_payload;
const runtimeConfig = input.runtime_config;
const projectId = input.project_id;

// Propagate cloud_mode from upstream
if (!cloudMode && runtimeConfig && runtimeConfig.cloud_mode) cloudMode = true;

// Required presence checks
if (!storeProfile || !storeProfile.store_id) {
  throw new Error('MISSING_ARTIFACT: store_profile with store_id is required. Run build-store-profile first.');
}
if (!marketIntelligence || !marketIntelligence.market_category) {
  throw new Error('MISSING_ARTIFACT: market_intelligence with market_category is required. Run build-market-intelligence first.');
}
if (!brandPositioning || !brandPositioning.brand_role) {
  throw new Error('MISSING_ARTIFACT: brand_positioning with brand_role is required. Run build-brand-positioning first.');
}
if (!Array.isArray(competitorClusters) || competitorClusters.length === 0) {
  throw new Error('MISSING_ARTIFACT: competitor_clusters must be a non-empty array. Run build-competitor-clusters first.');
}
if (!intakePayload) {
  throw new Error('MISSING_ARTIFACT: normalized_intake_payload is required. Run intake-store-input first.');
}
if (!runtimeConfig) {
  throw new Error('MISSING_RUNTIME_CONFIG: runtime_config is required.');
}
if (!projectId) {
  throw new Error('MISSING_INPUT: project_id is required.');
}

// Required store_profile fields
const profileRequired = ['store_id', 'vertical', 'price_positioning', 'store_type', 'catalog_type'];
const profileMissing = profileRequired.filter(function(f) { return !storeProfile[f]; });
if (profileMissing.length > 0) {
  throw new Error('MISSING_ARTIFACT: store_profile missing required fields: ' + profileMissing.join(', '));
}

// Required market_intelligence fields
if (!Array.isArray(marketIntelligence.core_problems) || marketIntelligence.core_problems.length === 0) {
  throw new Error('MISSING_ARTIFACT: market_intelligence.core_problems must be a non-empty array.');
}
if (!Array.isArray(marketIntelligence.positioning_goals) || marketIntelligence.positioning_goals.length === 0) {
  throw new Error('MISSING_ARTIFACT: market_intelligence.positioning_goals must be a non-empty array.');
}

// Required brand_positioning fields
if (!brandPositioning.value_proposition) {
  throw new Error('MISSING_ARTIFACT: brand_positioning.value_proposition is required.');
}
if (!Array.isArray(brandPositioning.differentiators) || brandPositioning.differentiators.length === 0) {
  throw new Error('MISSING_ARTIFACT: brand_positioning.differentiators must be a non-empty array.');
}

console.log('build-strategy-synthesis: inputs validated. cluster_count=' + competitorClusters.length + ', cloud=' + cloudMode);

return [{
  json: {
    project_id: projectId,
    runtime_config: runtimeConfig,
    store_profile: storeProfile,
    market_intelligence: marketIntelligence,
    brand_positioning: brandPositioning,
    competitor_clusters: competitorClusters,
    normalized_intake_payload: intakePayload,
    cloud_mode: cloudMode,
  },
}];

// build-strategy-synthesis — Build LLM Synthesis Prompt
// Assembles a structured cross-artifact synthesis prompt.
// Extracts key signals from all four upstream artifacts and asks the LLM to
// produce a strategic synthesis object.
//
// Evidence boundary:
//   - LLM inference from internal signals only.
//   - No external research, no crawling, no competitive intelligence APIs.
//   - All outputs are planning hypotheses requiring human verification.
//
// Phase 16: strategy_synthesis is the handlungsleitend artifact for
// downstream phases (offer-architecture, content-strategy, gtm-plan).

const input = $input.first().json;
const sp = input.store_profile;
const mi = input.market_intelligence;
const bp = input.brand_positioning;
const clusters = input.competitor_clusters || [];
const cloudMode = input.cloud_mode || false;

// ─── Extract Store Profile signals ──────────────────────────────────────────
const vertical = sp.vertical || 'unknown';
const pricePositioning = sp.price_positioning || 'unknown';
const storeType = sp.store_type || 'unknown';
const catalogType = sp.catalog_type || 'unknown';
const brandMaturity = sp.brand_maturity || 'new';
const assortmentShape = sp.assortment_shape || null;
const vpHint = sp.value_proposition_hint || null;
const brandVoiceHint = sp.brand_voice_hint || null;
const primaryMarket = sp.primary_market || 'unknown';
const openQuestions = (sp.open_questions || []).slice(0, 4);

// ─── Extract Market Intelligence signals ────────────────────────────────────
const marketCategory = mi.market_category || 'unknown';
const coreProblems = (mi.core_problems || []).slice(0, 5).map(function(p) {
  return typeof p === 'string' ? p : (p.problem || JSON.stringify(p));
});
const positioningGoals = (mi.positioning_goals || []).slice(0, 4).map(function(g) {
  return typeof g === 'string' ? g : (g.goal || JSON.stringify(g));
});
const audienceSegments = (mi.audience_segments || []).slice(0, 3).map(function(s) {
  return (s.segment_name || 'unknown') + (s.description ? ': ' + s.description.slice(0, 100) : '');
});
const trustFactors = (mi.trust_factors || []).slice(0, 3).map(function(t) {
  return typeof t === 'string' ? t : (t.factor || JSON.stringify(t));
});
const opportunityFlags = (mi.opportunity_flags || []).slice(0, 4);
const riskFlags = (mi.risk_flags || []).slice(0, 4);
const miUnknownStates = (mi.unknown_states || []).slice(0, 4);

// ─── Extract Brand Positioning signals ──────────────────────────────────────
const brandRole = bp.brand_role || 'unknown';
const valueProposition = bp.value_proposition || '';
const positioningStatement = bp.positioning_statement || '';
const differentiators = (bp.differentiators || []).slice(0, 5);
const brandTraits = (bp.brand_traits || []).slice(0, 4);
const toneStyle = (bp.tone_of_voice && bp.tone_of_voice.style) ? bp.tone_of_voice.style : 'unknown';
const messagingPillars = (bp.messaging_pillars || []).slice(0, 3).map(function(p) {
  return p.pillar_name + (p.description ? ': ' + p.description.slice(0, 80) : '');
});
const antiPositioning = (bp.anti_positioning || []).slice(0, 3);
const emotionalBenefits = (bp.emotional_benefits || []).slice(0, 3);
const confidenceBasis = bp.confidence_basis || null;

// ─── Extract Competitor Cluster signals ─────────────────────────────────────
const clusterSummaries = clusters.slice(0, 5).map(function(c, i) {
  const summary = [
    'Cluster ' + (i + 1) + ': ' + (c.cluster_name || 'unnamed') + ' [' + (c.cluster_role || 'unknown') + ']',
    '  Strengths: ' + (c.shared_strengths || []).slice(0, 2).join('; '),
    '  Weaknesses: ' + (c.shared_weaknesses || []).slice(0, 2).join('; '),
    '  Non-copyable: ' + (c.non_copyable_elements || []).slice(0, 2).join('; '),
    '  Opportunities to adapt: ' + (c.adaptation_opportunities || []).slice(0, 2).join('; '),
  ];
  if (c.strategic_summary) summary.push('  Strategic note: ' + c.strategic_summary);
  return summary.join('\n');
});

// ─── Build the prompt ────────────────────────────────────────────────────────
const prompt = [
  'You are a senior commerce strategist. Synthesize the following planning artifacts for a ' + vertical + ' store into a strategic synthesis JSON object.',
  '',
  '== STORE PROFILE ==',
  '- Vertical: ' + vertical,
  '- Store type: ' + storeType,
  '- Price positioning: ' + pricePositioning,
  '- Catalog type: ' + catalogType,
  '- Brand maturity: ' + brandMaturity,
  '- Primary market: ' + primaryMarket,
  assortmentShape ? '- Assortment shape: ' + assortmentShape : null,
  vpHint ? '- Value proposition hint: ' + vpHint : null,
  brandVoiceHint ? '- Brand voice hint: ' + brandVoiceHint : null,
  openQuestions.length > 0 ? '- Open questions from profile: ' + openQuestions.join('; ') : null,
  '',
  '== MARKET INTELLIGENCE ==',
  '- Market category: ' + marketCategory,
  '- Core problems this market solves:',
  coreProblems.map(function(p) { return '  · ' + p; }).join('\n'),
  '- Positioning goals (what to achieve vs competitors):',
  positioningGoals.map(function(g) { return '  · ' + g; }).join('\n'),
  '- Key audience segments:',
  audienceSegments.map(function(s) { return '  · ' + s; }).join('\n'),
  '- Trust factors: ' + trustFactors.join('; '),
  opportunityFlags.length > 0 ? '- Opportunity flags: ' + opportunityFlags.join('; ') : null,
  riskFlags.length > 0 ? '- Risk flags: ' + riskFlags.join('; ') : null,
  miUnknownStates.length > 0 ? '- Unknown states flagged: ' + miUnknownStates.map(function(u) { return typeof u === 'string' ? u : (u.domain + ': ' + u.unknown); }).join('; ') : null,
  '',
  '== BRAND POSITIONING ==',
  '- Brand role: ' + brandRole,
  '- Value proposition: ' + valueProposition,
  positioningStatement ? '- Positioning statement: ' + positioningStatement : null,
  '- Key differentiators: ' + differentiators.join('; '),
  '- Brand traits: ' + brandTraits.join(', '),
  '- Tone of voice: ' + toneStyle,
  messagingPillars.length > 0 ? '- Messaging pillars: ' + messagingPillars.join(' | ') : null,
  antiPositioning.length > 0 ? '- Anti-positioning (must NOT position as): ' + antiPositioning.join('; ') : null,
  emotionalBenefits.length > 0 ? '- Emotional benefits: ' + emotionalBenefits.join('; ') : null,
  confidenceBasis ? '- Positioning confidence: ' + (confidenceBasis.evidence_level || 'unknown') : null,
  '',
  '== COMPETITOR CLUSTERS (' + clusters.length + ' clusters) ==',
  clusterSummaries.join('\n\n'),
  '',
  '== SYNTHESIS TASK ==',
  'Produce a strategic synthesis JSON object with ALL of the following required fields:',
  '',
  '1. strategic_summary (string) — 2-4 sentence synthesis of where this store stands strategically: market context, brand positioning, competitive landscape, and the core strategic challenge.',
  '',
  '2. growth_thesis (object) — the core hypothesis about how this store grows:',
  '   { "statement": string (1 sentence), "rationale": string, "confidence": "high"|"medium"|"low"|"speculative", "depends_on": [string] }',
  '',
  '3. positioning_focus (object) — the primary positioning angle to pursue:',
  '   { "primary_angle": string, "rationale": string, "differentiating_from": [string], "supported_by": [string] }',
  '',
  '4. opportunity_priorities (array, minItems: 2) — top prioritized opportunities from all artifacts:',
  '   Each item: { "opportunity": string, "source": "market_intelligence"|"brand_positioning"|"competitor_clusters"|"store_profile"|"cross_signal", "priority": "high"|"medium"|"low", "rationale": string, "phase_implications": ["seo"|"aeo"|"gtm"|"offer"|"content"|"brand"|"ux"|"paid"] }',
  '',
  '5. risk_priorities (array, minItems: 2) — key risks and challenges:',
  '   Each item: { "risk": string, "source": "market_intelligence"|"brand_positioning"|"competitor_clusters"|"store_profile"|"cross_signal", "severity": "high"|"medium"|"low", "mitigation_hint": string }',
  '',
  '6. validation_questions (array, minItems: 3) — questions that require human validation before acting on this synthesis. Surfaces key assumptions.',
  '',
  'ALSO INCLUDE these optional fields when you have meaningful content:',
  '',
  '7. moat_hypotheses (array) — hypotheses about durable competitive advantage:',
  '   Each item: { "hypothesis": string, "type": "brand"|"catalog"|"customer-relationship"|"operations"|"content"|"pricing"|"expertise"|"mixed", "confidence": "high"|"medium"|"low"|"speculative", "evidence_basis": string, "risk": string }',
  '',
  '8. messaging_priorities (array) — priority messages to communicate:',
  '   Each item: { "message": string, "audience": string, "priority": "high"|"medium"|"low", "channel_relevance": ["seo"|"aeo"|"homepage"|"pdp"|"email"|"social"|"paid"|"content"], "rationale": string }',
  '',
  '9. offer_implications (array) — what this synthesis means for product/offer strategy:',
  '   Each item: { "implication": string, "action_hint": string, "urgency": "high"|"medium"|"low" }',
  '',
  '10. gtm_implications (array) — go-to-market channel implications:',
  '    Each item: { "implication": string, "channel": "seo"|"aeo"|"paid"|"social"|"email"|"content"|"partnerships"|"mixed", "priority": "high"|"medium"|"low" }',
  '',
  '11. confidence_notes (object) — overall confidence assessment:',
  '    { "overall_level": "high"|"medium"|"low"|"assumption-only", "primary_gaps": [string], "review_required": boolean, "basis_artifacts": ["store_profile"|"market_intelligence"|"brand_positioning"|"competitor_clusters"] }',
  '',
  '12. unknown_states (array) — unknown states carried forward from upstream phases:',
  '    Each item: { "domain": string, "unknown": string, "impact": "high"|"medium"|"low", "source_artifact": string }',
  '',
  'EVIDENCE BOUNDARY:',
  '- All analysis is LLM inference from the internal signals provided above.',
  '- Do NOT invent market data, competitor revenue, traffic figures, or conversion metrics.',
  '- Do NOT claim knowledge of events after your training cutoff.',
  '- Clearly surface uncertainty via confidence fields and unknown_states.',
  '- Treat all outputs as planning hypotheses requiring human review.',
  '',
  'Return ONLY valid JSON — no markdown code fences, no preamble, no explanation.',
].filter(function(line) { return line !== null; }).join('\n');

return [{
  json: {
    llm_prompt: prompt,
    project_id: input.project_id,
    runtime_config: input.runtime_config,
    store_profile: input.store_profile,
    market_intelligence: input.market_intelligence,
    brand_positioning: input.brand_positioning,
    competitor_clusters: input.competitor_clusters,
    normalized_intake_payload: input.normalized_intake_payload,
    cloud_mode: cloudMode,
  },
}];

// build-strategy-synthesis — Parse, Validate, and Write
//
// Steps:
//   1. Parse LLM JSON object response
//   2. Inline schema validation (required fields, enum values, minItems)
//   3. AJV full schema validation (self-hosted only)
//   4. Write strategy-synthesis.json artifact (self-hosted only)
//   5. Return strategy_synthesis inline (both modes) with envelope
//
// CLOUD MODE: steps 3 and 4 are skipped. Inline validation (step 2) always runs.

function buildRunId() {
  const ts = new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 14);
  const rand = Math.random().toString(36).slice(2, 6);
  return 'run-' + ts + '-' + rand;
}

let fs, path;
let cloudMode = false;
try {
  fs = require('fs');
  path = require('path');
} catch (_e) {
  cloudMode = true;
}

const llmOutput = $input.first().json;
const upstream = $node['Build LLM Synthesis Prompt'].json;

if (!cloudMode && upstream.cloud_mode) cloudMode = true;
if (!cloudMode && upstream.runtime_config && upstream.runtime_config.cloud_mode) cloudMode = true;

const projectId = upstream.project_id;
const runtimeConfig = upstream.runtime_config;
const storeProfile = upstream.store_profile;
const marketIntelligence = upstream.market_intelligence;
const brandPositioning = upstream.brand_positioning;
const competitorClusters = upstream.competitor_clusters;

// Extract text from OpenAI node (simplifyOutput: true → message.content)
const rawText = (llmOutput.message && llmOutput.message.content)
  ? llmOutput.message.content
  : (typeof llmOutput === 'string' ? llmOutput : JSON.stringify(llmOutput));

// ─── Step 1: Parse LLM response ─────────────────────────────────────────────
let synthesis;
try {
  let cleaned = rawText.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  }
  const parsed = JSON.parse(cleaned);
  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
    synthesis = parsed;
  } else {
    throw new Error('Expected a JSON object at root, got: ' + typeof parsed);
  }
} catch (err) {
  throw new Error(
    'LLM_PARSE_ERROR: Failed to parse LLM response as JSON object: ' + err.message +
    '. Raw response (first 500 chars): ' + String(rawText).slice(0, 500)
  );
}

// ─── Step 2: Inline schema validation ───────────────────────────────────────
const REQUIRED_FIELDS = [
  'strategic_summary',
  'growth_thesis',
  'positioning_focus',
  'opportunity_priorities',
  'risk_priorities',
  'validation_questions',
];
const ARRAY_FIELDS_MIN1 = ['opportunity_priorities', 'risk_priorities', 'validation_questions'];
const CONFIDENCE_ENUM = ['high', 'medium', 'low', 'speculative'];
const PRIORITY_ENUM = ['high', 'medium', 'low'];
const SEVERITY_ENUM = ['high', 'medium', 'low'];
const SOURCE_ENUM = ['market_intelligence', 'brand_positioning', 'competitor_clusters', 'store_profile', 'cross_signal'];
const MOAT_TYPE_ENUM = ['brand', 'catalog', 'customer-relationship', 'operations', 'content', 'pricing', 'expertise', 'mixed'];
const GTM_CHANNEL_ENUM = ['seo', 'aeo', 'paid', 'social', 'email', 'content', 'partnerships', 'mixed'];

const validationErrors = [];

// Required top-level fields
REQUIRED_FIELDS.forEach(function(f) {
  if (synthesis[f] === undefined || synthesis[f] === null || synthesis[f] === '') {
    validationErrors.push('missing required field "' + f + '"');
  }
});

// strategic_summary: string
if (synthesis.strategic_summary && typeof synthesis.strategic_summary !== 'string') {
  validationErrors.push('strategic_summary must be a string');
}

// growth_thesis: object with required subfields
if (synthesis.growth_thesis && typeof synthesis.growth_thesis === 'object') {
  if (!synthesis.growth_thesis.statement) validationErrors.push('growth_thesis.statement is required');
  if (!synthesis.growth_thesis.rationale) validationErrors.push('growth_thesis.rationale is required');
  if (synthesis.growth_thesis.confidence && !CONFIDENCE_ENUM.includes(synthesis.growth_thesis.confidence)) {
    validationErrors.push('growth_thesis.confidence must be one of: ' + CONFIDENCE_ENUM.join(', '));
  }
} else if (synthesis.growth_thesis) {
  validationErrors.push('growth_thesis must be an object');
}

// positioning_focus: object with required subfields
if (synthesis.positioning_focus && typeof synthesis.positioning_focus === 'object') {
  if (!synthesis.positioning_focus.primary_angle) validationErrors.push('positioning_focus.primary_angle is required');
  if (!synthesis.positioning_focus.rationale) validationErrors.push('positioning_focus.rationale is required');
} else if (synthesis.positioning_focus) {
  validationErrors.push('positioning_focus must be an object');
}

// Array fields with minItems: 1
ARRAY_FIELDS_MIN1.forEach(function(f) {
  if (!Array.isArray(synthesis[f]) || synthesis[f].length === 0) {
    validationErrors.push('"' + f + '" must be a non-empty array (minItems: 1)');
  }
});

// opportunity_priorities items
if (Array.isArray(synthesis.opportunity_priorities)) {
  synthesis.opportunity_priorities.forEach(function(item, i) {
    const label = 'opportunity_priorities[' + i + ']';
    if (!item.opportunity) validationErrors.push(label + ': missing required field "opportunity"');
    if (item.source && !SOURCE_ENUM.includes(item.source)) {
      validationErrors.push(label + ': source "' + item.source + '" not in enum');
    }
    if (item.priority && !PRIORITY_ENUM.includes(item.priority)) {
      validationErrors.push(label + ': priority "' + item.priority + '" not in enum');
    }
  });
}

// risk_priorities items
if (Array.isArray(synthesis.risk_priorities)) {
  synthesis.risk_priorities.forEach(function(item, i) {
    const label = 'risk_priorities[' + i + ']';
    if (!item.risk) validationErrors.push(label + ': missing required field "risk"');
    if (item.source && !SOURCE_ENUM.includes(item.source)) {
      validationErrors.push(label + ': source "' + item.source + '" not in enum');
    }
    if (item.severity && !SEVERITY_ENUM.includes(item.severity)) {
      validationErrors.push(label + ': severity "' + item.severity + '" not in enum');
    }
  });
}

// moat_hypotheses items (optional array)
if (synthesis.moat_hypotheses !== undefined && synthesis.moat_hypotheses !== null) {
  if (!Array.isArray(synthesis.moat_hypotheses)) {
    validationErrors.push('moat_hypotheses must be an array');
  } else {
    synthesis.moat_hypotheses.forEach(function(item, i) {
      const label = 'moat_hypotheses[' + i + ']';
      if (!item.hypothesis) validationErrors.push(label + ': missing required field "hypothesis"');
      if (item.type && !MOAT_TYPE_ENUM.includes(item.type)) {
        validationErrors.push(label + ': type "' + item.type + '" not in enum');
      }
      if (item.confidence && !CONFIDENCE_ENUM.includes(item.confidence)) {
        validationErrors.push(label + ': confidence "' + item.confidence + '" not in enum');
      }
    });
  }
}

// gtm_implications items (optional array)
if (synthesis.gtm_implications !== undefined && synthesis.gtm_implications !== null) {
  if (!Array.isArray(synthesis.gtm_implications)) {
    validationErrors.push('gtm_implications must be an array');
  } else {
    synthesis.gtm_implications.forEach(function(item, i) {
      const label = 'gtm_implications[' + i + ']';
      if (!item.implication) validationErrors.push(label + ': missing required field "implication"');
      if (item.channel && !GTM_CHANNEL_ENUM.includes(item.channel)) {
        validationErrors.push(label + ': channel "' + item.channel + '" not in enum');
      }
    });
  }
}

if (validationErrors.length > 0) {
  throw new Error('SCHEMA_VIOLATION: ' + validationErrors.join(' | '));
}

// ─── Step 3: AJV full validation — self-hosted only ─────────────────────────
const cloudWarnings = [];
if (!cloudMode) {
  try {
    const Ajv = require('ajv/dist/ajv.js') || require('ajv');
    const ajv = new Ajv({ allErrors: true, strict: false });
    const schemaFile = path.join(runtimeConfig.ajv_schema_path, 'strategy-synthesis.schema.json');
    const schema = JSON.parse(fs.readFileSync(schemaFile, 'utf8'));
    const validate = ajv.compile(schema);
    const valid = validate(synthesis);
    if (!valid) {
      const errs = (validate.errors || []).map(function(e) { return e.instancePath + ' ' + e.message; }).join('; ');
      throw new Error('AJV_VALIDATION_FAILED: ' + errs);
    }
  } catch (e) {
    if (e.message && e.message.startsWith('AJV_VALIDATION_FAILED')) throw e;
    cloudWarnings.push('AJV schema validation skipped: ' + e.message);
  }
} else {
  cloudWarnings.push('AJV schema validation skipped — cloud mode (no local schema files). Inline validation passed.');
}

// ─── Step 4: Write artifact — self-hosted only ──────────────────────────────
let artifactPath = null;
if (!cloudMode) {
  try {
    const projectDir = path.join(runtimeConfig.project_root, projectId);
    if (!fs.existsSync(projectDir)) fs.mkdirSync(projectDir, { recursive: true });
    artifactPath = path.join(projectDir, 'strategy-synthesis.json');
    fs.writeFileSync(artifactPath, JSON.stringify(synthesis, null, 2), 'utf8');
  } catch (e) {
    cloudWarnings.push('Artifact write skipped: ' + e.message);
  }
} else {
  cloudWarnings.push('Artifact write skipped — cloud mode (no filesystem).');
}

// ─── Log summary ─────────────────────────────────────────────────────────────
const oppCount = Array.isArray(synthesis.opportunity_priorities) ? synthesis.opportunity_priorities.length : 0;
const riskCount = Array.isArray(synthesis.risk_priorities) ? synthesis.risk_priorities.length : 0;
const moatCount = Array.isArray(synthesis.moat_hypotheses) ? synthesis.moat_hypotheses.length : 0;
console.log(
  'build-strategy-synthesis: completed.' +
  ' opportunities=' + oppCount +
  ', risks=' + riskCount +
  ', moats=' + moatCount +
  ', cloud=' + cloudMode
);

// ─── Build runtime envelope ──────────────────────────────────────────────────
const runId = buildRunId();
const executionTs = new Date().toISOString();

const envelope = {
  runtime: {
    run_id: runId,
    phase_id: 'build-strategy-synthesis',
    execution_ts: executionTs,
    cloud_mode: cloudMode,
    env: cloudMode ? 'cloud-smoke' : (runtimeConfig.env || 'dev'),
    schema_version: '1.0'
  },
  store: {
    project_id: projectId,
    artifact_name: 'strategy-synthesis',
    artifact_path: artifactPath
  },
  status: {
    code: 'SUCCESS',
    completed_at: executionTs,
    fatal_errors: [],
    warnings: cloudWarnings,
    retryable: false
  },
  diagnostics: {
    input_summary: {
      project_id: projectId,
      vertical: storeProfile.vertical,
      market_category: marketIntelligence.market_category,
      brand_role: brandPositioning.brand_role,
      cluster_count: competitorClusters.length,
    },
    output_summary: {
      opportunity_count: oppCount,
      risk_count: riskCount,
      moat_hypothesis_count: moatCount,
      has_messaging_priorities: Array.isArray(synthesis.messaging_priorities) && synthesis.messaging_priorities.length > 0,
      has_gtm_implications: Array.isArray(synthesis.gtm_implications) && synthesis.gtm_implications.length > 0,
      has_offer_implications: Array.isArray(synthesis.offer_implications) && synthesis.offer_implications.length > 0,
      has_unknown_states: Array.isArray(synthesis.unknown_states) && synthesis.unknown_states.length > 0,
      validation_question_count: Array.isArray(synthesis.validation_questions) ? synthesis.validation_questions.length : 0,
      confidence_level: (synthesis.confidence_notes && synthesis.confidence_notes.overall_level) || 'unknown'
    },
    validation: {
      schema_ref: 'schemas/strategy-synthesis.schema.json',
      result: cloudMode ? 'SKIPPED' : (cloudWarnings.some(function(w) { return w.includes('AJV schema validation skipped'); }) ? 'SKIPPED' : 'PASS'),
      errors: [],
      warnings: cloudMode ? ['AJV validation skipped — cloud mode'] : []
    },
    lineage: {
      upstream_phases: [
        'resolve-runtime-config',
        'intake-store-input',
        'build-store-profile',
        'build-market-intelligence',
        'build-brand-positioning',
        'build-competitor-clusters',
      ],
      upstream_artifacts: [
        'store_profile',
        'market_intelligence',
        'brand_positioning',
        'competitor_clusters',
        'normalized_intake_payload',
      ]
    },
    missing_data: []
  }
};

return [{
  json: {
    project_id: projectId,
    artifact_name: 'strategy-synthesis',
    artifact_path: artifactPath,
    strategy_synthesis: synthesis,
    runtime_config: runtimeConfig,
    status: 'SUCCESS',
    cloud_mode: cloudMode,
    cloud_warnings: cloudWarnings,
    notes: [],
    envelope: envelope,
  },
}];
